

-- COSMOS
select count(*)/12
from  fichsrv.tre_membership
where tfm_include_flag = 1 
	and global_cap = 'NA'
	and fin_product_level_3 <> 'INSTITUTIONAL'
	and sgr_source_name = 'COSMOS'
	and fin_brand = 'M&R'
	and fin_inc_year = 2024
; 
-- NICE
select count(*)/12
from fichsrv.tre_membership
where tfm_include_flag = 1 
	and nce_tadm_dec_risk_type  = 'FFS'
	and fin_product_level_3 <> 'INSTITUTIONAL'
	and sgr_source_name = 'NICE'
	and fin_brand = 'M&R'
	
	
-- COSMOS ISNP
select count(*)/12
from fichsrv.tre_membership
where --tfm_include_flag = 1 
	--and global_cap = 'NA'
	fin_product_level_3 = 'INSTITUTIONAL'
	--and sgr_source_name = 'COSMOS'
	--and fin_brand = 'M&R'
	and fin_inc_year = 2024
;

select count(*)/12
from fichsrv.tre_membership
where --tfm_include_flag = 1 
	--and global_cap = 'NA'
	fin_product_level_3 = 'INSTITUTIONAL'
	--and sgr_source_name = 'COSMOS'
	and fin_brand = 'C&S'
	and fin_inc_year = 2024
	and sgr_source_name = 'CSP'
	and migration_source != 'OAH'
	and global_cap = 'NA'
;


-- COSMOS ISNP
select count(*)/12
from fichsrv.tre_membership
where fin_product_level_3 = 'INSTITUTIONAL'
	and fin_inc_year = 2024
	and sgr_source_name = 'COSMOS'
;

-- CSP ISNP
select count(*)/12
from fichsrv.tre_membership
where fin_product_level_3 = 'INSTITUTIONAL'
	and fin_inc_year = 2024
	and sgr_source_name = 'CSP'
;

select count(*)/12
from fichsrv.tre_membership
where fin_product_level_3 = 'INSTITUTIONAL'
	and fin_inc_year = 2024
	and sgr_source_name = 'NICE'
;

select count(*)
from fichsrv.tre_membership
where fin_inc_year = 2024 and fin_brand = 'M&R' and sgr_source_name = 'NICE' and nce_tadm_dec_risk_type in ('FFS', 'PHYSICIAN') and tfm_include_flag = 1 and fin_product_level_3 <> 'INSTITUTIONAL'
;
-- 2,087,181

select count(*)
from fichsrv.tre_membership
where fin_inc_year = 2024 and fin_brand = 'M&R' and sgr_source_name = 'NICE' and nce_tadm_dec_risk_type in ('FFS') and tfm_include_flag = 1 and fin_product_level_3 <> 'INSTITUTIONAL'
;
